import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

/**
 * Função auxiliar para executar chamadas à API Gemini com lógica de re-tentativa (retry)
 */
async function executeWithRetry(model: string, prompt: string, systemInstruction?: string, maxRetries = 3): Promise<string> {
  let lastError: any = null;

  for (let i = 0; i < maxRetries; i++) {
    try {
      // Create a new GoogleGenAI instance right before making an API call to ensure it always uses the most up-to-date API key
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const response: GenerateContentResponse = await ai.models.generateContent({
        model: model,
        contents: prompt, // Use simple string prompt for basic text tasks
        config: {
          systemInstruction: systemInstruction || "Você é um consultor estratégico de elite da Monte & Chaisa, uma empresa moçambicana líder em imobiliária, manutenção técnica e gestão hoteleira.",
          temperature: 0.8,
          topP: 0.95,
        }
      });

      // Directly access .text property from GenerateContentResponse
      return response.text || "Sem resposta.";
    } catch (error: any) {
      lastError = error;
      const errorMsg = error?.message || String(error);
      // Implement robust handling for API errors (e.g., 500 or fetch errors) with exponential backoff
      if ((errorMsg.includes("500") || errorMsg.includes("fetch")) && i < maxRetries - 1) {
        await new Promise(resolve => setTimeout(resolve, Math.pow(2, i) * 1000));
        continue;
      }
      break;
    }
  }
  return "Erro ao conectar com a IA.";
}

export const getStrategicInsight = async (context: string) => {
  const prompt = `Analise estes dados da Monte & Chaisa e forneça uma diretriz executiva curta (máx 2 frases): ${context}.`;
  return await executeWithRetry('gemini-3-pro-preview', prompt);
};

export const chatWithMonteAI = async (userMessage: string, businessData: any) => {
  const system = `Você é o Monte AI, o cérebro estratégico do ERP Monte & Chaisa. 
  Dados Atuais: Receitas ${businessData.revenue}MT, Despesas ${businessData.expenses}MT, Staff ${businessData.employees}, Imóveis ${businessData.properties}.
  Contexto: Beira, Moçambique. Seja profissional, direto e use Português de Moçambique quando apropriado.`;

  return await executeWithRetry('gemini-3-pro-preview', userMessage, system);
};

export const generateJobDescription = async (jobTitle: string, area: string, location: string) => {
  const prompt = `Gere uma descrição de vaga PROFISSIONAL para "${jobTitle}" em "${area}", na Monte & Chaisa (${location}). Comece direto no título.`;
  return await executeWithRetry('gemini-3-flash-preview', prompt);
};

import React, { useState, useEffect } from 'react';
import { UserRole, User } from './types';
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import Navbar from './components/Navbar';
import Footer from './components/Footer';
import { supabase } from './supabaseClient';

// ERP Views
import DashboardView from './views/DashboardView';
import FinanceView from './views/FinanceView';
import HRView from './views/HRView';
import ProjectsView from './views/ProjectsView';
import PlansView from './views/PlansView';
import ReportsView from './views/ReportsView';
import AdminView from './views/AdminView';
import CatalogView from './views/CatalogView';
import FleetView from './views/FleetView';
import LoginView from './views/LoginView';
import OverviewView from './views/OverviewView';

// Public Views
import HomeView from './views/HomeView';
import PropertyListView from './views/PropertyListView';
import PropertyDetailView from './views/PropertyDetailView';
import ServicesView from './views/ServicesView';
import ContactView from './views/ContactView';
import AboutView from './views/AboutView';
import CareerView from './views/CareerView';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [currentPath, setCurrentPath] = useState('home');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [selectedPropertyId, setSelectedPropertyId] = useState<string | null>(null);
  const [isInitializing, setIsInitializing] = useState(true);

  useEffect(() => {
    // 1. Verificar sessão atual ao carregar
    checkUser();

    // 2. Escutar mudanças de autenticação
    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (event, session) => {
      if (session) {
        await fetchAndSetUser(session.user);
      } else {
        setCurrentUser(null);
        const erpPaths = ['dashboard', 'finance', 'hr', 'projects', 'plans', 'reports', 'admin', 'catalog', 'fleet', 'overview'];
        if (erpPaths.includes(currentPath)) {
          setCurrentPath('home');
        }
      }
    });

    return () => subscription.unsubscribe();
  }, []);

  async function checkUser() {
    try {
      const { data: { session }, error } = await supabase.auth.getSession();
      if (error) throw error;
      if (session?.user) {
        await fetchAndSetUser(session.user);
      }
    } catch (err) {
      console.error("Initialization Error:", err);
    } finally {
      setIsInitializing(false);
    }
  }

  async function fetchAndSetUser(sbUser: any) {
    try {
      // Buscar detalhes do funcionário
      const { data: emp, error } = await supabase
        .from('employees')
        .select('*')
        .eq('email', sbUser.email)
        .maybeSingle();

      const user: User = {
        id: sbUser.id,
        name: emp?.name || sbUser.email.split('@')[0],
        email: sbUser.email,
        role: emp?.role || UserRole.EMPLOYEE,
        avatar: emp?.avatar || `https://picsum.photos/seed/${sbUser.id}/100`,
        permissions: emp?.permissions || []
      };
      setCurrentUser(user);
      if (currentPath === 'login') setCurrentPath('dashboard');
    } catch (err) {
      console.error("Error fetching user profile:", err);
      setCurrentUser({
        id: sbUser.id,
        name: sbUser.email.split('@')[0],
        email: sbUser.email,
        role: UserRole.EMPLOYEE,
        avatar: `https://picsum.photos/seed/${sbUser.id}/100`,
        permissions: []
      });
    }
  }

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setCurrentUser(null);
    setCurrentPath('home');
  };

  const handleViewProperty = (id: string) => {
    setSelectedPropertyId(id);
    setCurrentPath('imovel-detalhes');
    window.scrollTo(0, 0);
  };

  const isERPRoute = ['dashboard', 'finance', 'hr', 'projects', 'plans', 'reports', 'admin', 'catalog', 'fleet', 'overview'].includes(currentPath);

  const renderContent = () => {
    switch (currentPath) {
      case 'home': return <HomeView onNavigate={setCurrentPath} onViewProperty={handleViewProperty} />;
      case 'imoveis': return <PropertyListView onViewProperty={handleViewProperty} />;
      case 'imovel-detalhes': return <PropertyDetailView propertyId={selectedPropertyId} onBack={() => setCurrentPath('imoveis')} />;
      case 'servicos': return <ServicesView />;
      case 'contato': return <ContactView />;
      case 'sobre': return <AboutView />;
      case 'carreira': return <CareerView />;
      case 'login': return (
        <LoginView 
          onLoginSuccess={(user) => {
            setCurrentUser(user);
            setCurrentPath('dashboard');
          }} 
          onBack={() => setCurrentPath('home')}
        />
      );
      case 'dashboard': return <DashboardView />;
      case 'catalog': return <CatalogView />;
      case 'finance': return <FinanceView />;
      case 'hr': return <HRView />;
      case 'fleet': return <FleetView />;
      case 'projects': return <ProjectsView />;
      case 'plans': return <PlansView />;
      case 'reports': return <ReportsView />;
      case 'overview': return <OverviewView />;
      case 'admin': return <AdminView currentUser={currentUser} />;
      default: return <HomeView onNavigate={setCurrentPath} onViewProperty={handleViewProperty} />;
    }
  };

  if (isInitializing) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-8 text-center">
        <div className="w-20 h-20 bg-indigo-600 rounded-[2.5rem] flex items-center justify-center p-4 shadow-2xl animate-pulse mb-6">
          <img src="https://i.ibb.co/LzfNdf7Y/building-logo.png" className="w-full h-full object-contain brightness-0 invert" alt="Loading" />
        </div>
        <h2 className="text-xl font-black text-slate-900 animate-pulse uppercase tracking-widest">Sincronizando Monte & Chaisa...</h2>
      </div>
    );
  }

  if (isERPRoute && currentUser) {
    return (
      <div className="flex h-screen overflow-hidden bg-slate-50">
        <Sidebar 
          currentPath={currentPath} 
          onNavigate={setCurrentPath} 
          user={currentUser}
          isOpen={isSidebarOpen}
          toggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)}
        />
        <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
          <Header 
            user={currentUser} 
            onLogout={handleLogout} 
            onOpenSidebar={() => setIsSidebarOpen(true)} 
            onViewProperty={handleViewProperty}
          />
          <main className="flex-1 overflow-y-auto p-4 md:p-8">
            <div className="max-w-7xl mx-auto">{renderContent()}</div>
          </main>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-white flex flex-col">
      <Navbar currentPath={currentPath} onNavigate={setCurrentPath} isLoggedIn={!!currentUser} />
      <main className="flex-1">
        {renderContent()}
      </main>
      <Footer onNavigate={setCurrentPath} />
    </div>
  );
};

export default App;

import React from 'react';
import { ERP_NAVIGATION } from '../constants';
import { UserRole, User } from '../types';
import { X } from 'lucide-react';

interface SidebarProps {
  currentPath: string;
  onNavigate: (path: string) => void;
  user: User;
  isOpen: boolean;
  toggleSidebar: () => void;
}

const Sidebar: React.FC<SidebarProps> = ({ currentPath, onNavigate, user, isOpen, toggleSidebar }) => {
  const filteredNav = ERP_NAVIGATION.filter(item => {
    if (!item.permission) return true;
    if (user.role === UserRole.ADMIN) return true;
    return user.permissions?.includes(item.permission);
  });

  return (
    <div className={`fixed inset-y-0 left-0 z-50 transform ${isOpen ? 'translate-x-0' : '-translate-x-full'} md:relative md:translate-x-0 transition duration-300 ease-in-out bg-slate-950 text-slate-300 w-64 flex flex-col shadow-2xl`}>
      <div className="p-8 flex items-center justify-between border-b border-white/5">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center p-1.5 shadow-lg shadow-indigo-500/20">
            <img src="https://i.ibb.co/LzfNdf7Y/building-logo.png" alt="Monte & Chaisa" className="w-full h-full object-contain brightness-0 invert" />
          </div>
          <span className="text-xl font-black text-white tracking-tighter leading-none">Monte<br/><span className="text-indigo-400">& Chaisa</span></span>
        </div>
        <button onClick={toggleSidebar} className="md:hidden text-slate-400 hover:text-white">
          <X size={24} />
        </button>
      </div>

      <nav className="flex-1 px-4 py-8 space-y-1.5 overflow-y-auto custom-scrollbar-dark">
        <div className="mb-6 px-4 text-[9px] font-black text-slate-600 uppercase tracking-[0.3em]">Ecossistema Monte & Chaisa</div>
        {filteredNav.map((item) => (
          <button
            key={item.path}
            onClick={() => {
              onNavigate(item.path);
              if (window.innerWidth < 768) toggleSidebar();
            }}
            className={`w-full flex items-center gap-3 px-4 py-3.5 rounded-2xl transition-all duration-300 group ${
              currentPath === item.path 
              ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-600/20' 
              : 'hover:bg-white/5 hover:text-white'
            }`}
          >
            <span className={`${currentPath === item.path ? 'text-white' : 'text-slate-500 group-hover:text-indigo-400'}`}>
              {item.icon}
            </span>
            <span className="font-bold text-xs uppercase tracking-widest">{item.name}</span>
          </button>
        ))}
      </nav>

      <div className="p-6 border-t border-white/5 bg-black/20">
        <div className="bg-white/5 rounded-2xl p-5 border border-white/5">
          <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest mb-3 flex items-center gap-2">
            <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-pulse"></div> Sessão Segura
          </p>
          <div className="flex justify-between items-center mb-1">
            <span className="text-[10px] font-bold text-white truncate max-w-[120px]">{user.role}</span>
          </div>
          <div className="w-full bg-slate-800 h-1 rounded-full overflow-hidden mt-2">
            <div className="h-full bg-indigo-500 w-full"></div>
          </div>
        </div>
      </div>
    </div>
  );
};

