           <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-500/10 rounded-full blur-2xl"></div>
           <div className="flex items-center gap-4 relative z-10">
              <div className="w-3 h-3 bg-emerald-500 rounded-full animate-pulse shadow-[0_0_15px_rgba(16,185,129,0.8)]"></div>
              <div>
                 <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Sincronização Monte & Chaisa Cloud</p>
                 <p className="text-sm font-bold">100% Ativa</p>
              </div>
           </div>
           <div className="w-px h-10 bg-white/10 hidden md:block"></div>
           <div className="hidden md:flex flex-col items-end relative z-10">
              <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Sistema Operacional</p>
              <p className="text-sm font-bold">{new Date().toLocaleDateString('pt-MZ')}</p>
           </div>
        </div>
      </div>

      {/* KPI Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {[
          { label: 'Fluxo Caixa', value: `${(stats.revenue - stats.expenses).toLocaleString()} MT`, icon: <Wallet className="text-indigo-600" />, trend: 'Saldo Disponível', color: 'indigo' },
          { label: 'Equipa Monte', value: stats.employees, icon: <Users className="text-emerald-600" />, trend: 'Colaboradores Ativos', color: 'emerald' },
          { label: 'Portfólio', value: stats.properties, icon: <Home className="text-blue-600" />, trend: 'Imóveis Registados', color: 'blue' },
          { label: 'Inbox', value: stats.contacts, icon: <MessageSquare className="text-rose-600" />, trend: 'Novas Mensagens', color: 'rose' },
        ].map((kpi, idx) => (
