} from 'recharts';
import { supabase } from '../supabaseClient';
import { JobApplication } from '../types';
import { getStrategicInsight, chatWithMonteAI } from '../geminiService';
import TodoList from '../components/TodoList';

const DashboardView: React.FC = () => {
  const [stats, setStats] = useState({ 
    revenue: 0, 
    expenses: 0, 
    employees: 0, 
    properties: 0, 
    contacts: 0,
    pendingApps: 0 
  });
  const [recentMessages, setRecentMessages] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [aiInsight, setAiInsight] = useState<string>('Analizando pulso da Monte & Chaisa...');

  // AI Chat States
  const [aiChatOpen, setAiChatOpen] = useState(false);
  const [chatInput, setChatInput] = useState('');
  const [chatMessages, setChatMessages] = useState<{role: 'user' | 'ai', text: string}[]>([
    { role: 'ai', text: 'Olá! Sou o Monte AI. Como posso ajudar com a gestão estratégica da Monte & Chaisa hoje?' }
  ]);
  const [isAiTyping, setIsAiTyping] = useState(false);

  useEffect(() => {
    fetchGlobalStats();
  }, []);

  async function fetchGlobalStats() {
    setLoading(true);
    try {
      const [txRes, empRes, propRes, contactRes, msgListRes, appCountRes] = await Promise.all([
        supabase.from('transactions').select('*'),
        supabase.from('employees').select('*', { count: 'exact', head: true }),
        supabase.from('properties').select('*', { count: 'exact', head: true }),
        supabase.from('contact_requests').select('*', { count: 'exact', head: true }),
        supabase.from('contact_requests').select('*').order('created_at', { ascending: false }).limit(3),
        supabase.from('job_applications').select('*', { count: 'exact', head: true }).eq('status', 'Pendente')
      ]);

      const txs = txRes.data || [];
      const rev = txs.filter(t => t.type === 'RECEITA').reduce((a, b) => a + Number(b.amount || 0), 0);
      const exp = txs.filter(t => t.type === 'DESPESA').reduce((a, b) => a + Number(b.amount || 0), 0);

      const newStats = {
        revenue: rev, 
        expenses: exp,
        employees: empRes.count || 0,
        properties: propRes.count || 0, 
        contacts: contactRes.count || 0,
        pendingApps: appCountRes.count || 0
      };
      setStats(newStats);
      setRecentMessages(msgListRes.data || []);

      const insight = await getStrategicInsight(`Fluxo: ${rev-exp}MT, Imóveis: ${propRes.count}, Staff: ${empRes.count}, Candidaturas: ${appCountRes.count}`);
      setAiInsight(insight);
    } catch (error: any) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  }

  const handleSendToAI = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!chatInput.trim() || isAiTyping) return;

    const userMsg = chatInput;
    setChatMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setChatInput('');
    setIsAiTyping(true);

    const response = await chatWithMonteAI(userMsg, stats);
    setChatMessages(prev => [...prev, { role: 'ai', text: response }]);
    setIsAiTyping(false);
  };

  const chartData = useMemo(() => [
    { name: 'Receitas', value: stats.revenue, color: '#6366f1' },
    { name: 'Despesas', value: stats.expenses, color: '#f43f5e' }
  ], [stats]);

  if (loading) return (
    <div className="h-full flex flex-col items-center justify-center py-32 gap-6 bg-slate-50">
      <div className="w-16 h-16 bg-indigo-600 rounded-[2rem] flex items-center justify-center p-4 shadow-2xl animate-bounce">
         <img src="https://i.ibb.co/LzfNdf7Y/building-logo.png" className="w-full h-full object-contain brightness-0 invert" alt="Monte Logo" />
      </div>
      <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.4em] animate-pulse">Sincronizando Monte & Chaisa...</p>
    </div>
  );

  return (
    <div className="space-y-10 animate-in fade-in duration-700 pb-20">
      {/* Executive Insights & Status Row */}
      <div className="grid grid-cols-1 xl:grid-cols-4 gap-6">
        {/* AI Insight Card */}
        <div className="xl:col-span-2 bg-white px-10 py-8 rounded-[3.5rem] border border-slate-100 shadow-sm flex items-center justify-between">
          <div className="flex items-center gap-6">
             <div className="w-16 h-16 bg-indigo-50 text-indigo-600 rounded-3xl flex items-center justify-center shadow-inner">
               <Bot size={32} />
             </div>
             <div>
                <p className="text-[9px] font-black text-indigo-500 uppercase tracking-widest mb-1 flex items-center gap-2">
                  <Sparkles size={12} className="animate-pulse" /> Monte AI Assistant
                </p>
                <h2 className="text-xl font-black text-slate-900 tracking-tight leading-tight">"{aiInsight}"</h2>
             </div>
          </div>
          <button onClick={() => setAiChatOpen(true)} className="px-6 py-3 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-slate-900 transition-all shadow-xl shadow-indigo-600/20 active:scale-95 ml-4 hidden sm:block">Consultar IA</button>
        </div>

        {/* Pending Job Applications Widget */}
        <div className="bg-indigo-600 px-10 py-8 rounded-[3.5rem] text-white flex items-center justify-between shadow-xl shadow-indigo-600/20 group hover:bg-slate-900 transition-all">
           <div className="flex items-center gap-5">
              <div className="w-14 h-14 bg-white/20 rounded-2xl flex items-center justify-center">
                 <Briefcase size={28} />
              </div>
              <div>
                 <p className="text-[9px] font-black text-indigo-200 uppercase tracking-widest">Candidaturas</p>
                 <h2 className="text-2xl font-black">{stats.pendingApps} <span className="text-xs font-bold text-indigo-300">Pendentes</span></h2>
              </div>
           </div>
           <button className="p-3 bg-white/10 group-hover:bg-white/20 rounded-xl transition-all">
              <ArrowRight size={20} />
           </button>
        </div>

        {/* Sync Status Widget */}
        <div className="bg-slate-900 px-10 py-8 rounded-[3.5rem] text-white flex items-center justify-between shadow-2xl relative overflow-hidden border border-white/5">
           <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-500/10 rounded-full blur-2xl"></div>
           <div className="flex items-center gap-4 relative z-10">
              <div className="w-3 h-3 bg-emerald-500 rounded-full animate-pulse shadow-[0_0_15px_rgba(16,185,129,0.8)]"></div>
              <div>
                 <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest leading-tight mb-1">Status Cloud</p>
                 <p className="text-sm font-bold">100% Sincronizado</p>
              </div>
           </div>
           <div className="relative z-10 text-right">
              <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest leading-tight mb-1">Moz Time</p>
              <p className="text-sm font-bold">{new Date().toLocaleDateString('pt-MZ')}</p>
           </div>
        </div>
      </div>

      {/* KPI Grid - 5 Columns */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-5 gap-6">
        {[
          { label: 'Fluxo Caixa', value: `${(stats.revenue - stats.expenses).toLocaleString()} MT`, icon: <Wallet className="text-indigo-600" />, trend: 'Saldo Disponível' },
          { label: 'Equipa Monte', value: stats.employees, icon: <Users className="text-emerald-600" />, trend: 'Colaboradores Ativos' },
          { label: 'Portfólio', value: stats.properties, icon: <Home className="text-blue-600" />, trend: 'Imóveis Registados' },
          { label: 'Inbox', value: stats.contacts, icon: <MessageSquare className="text-rose-600" />, trend: 'Pedidos de Contacto' },
          { label: 'Recrutamento', value: stats.pendingApps, icon: <Briefcase className="text-amber-600" />, trend: 'Candidatos Novos' },
        ].map((kpi, idx) => (
          <div key={idx} className="bg-white p-8 rounded-[3rem] border border-slate-100 shadow-sm hover:shadow-2xl transition-all group overflow-hidden relative">
            <div className="absolute top-0 right-0 w-24 h-24 bg-slate-50 rounded-full translate-x-10 -translate-y-10 group-hover:scale-125 transition-transform duration-700"></div>
            <div className="relative z-10">
              <div className="flex items-center gap-4 mb-4">
                <div className="p-3 bg-slate-50 rounded-2xl text-slate-600 group-hover:bg-white group-hover:shadow-md transition-all">{kpi.icon}</div>
                <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{kpi.label}</span>
              </div>
              <h3 className="text-2xl font-black text-slate-900 tracking-tight mb-1">{kpi.value}</h3>
              <p className="text-[8px] font-bold text-slate-400 uppercase tracking-widest">{kpi.trend}</p>
            </div>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-3 gap-10">
        <div className="xl:col-span-2 space-y-10">
          <div className="bg-white p-12 rounded-[4rem] border border-slate-100 shadow-sm">
             <div className="flex items-center justify-between mb-12">
                <div>
                  <h3 className="text-2xl font-black text-slate-900 tracking-tight">Análise de Rendimento</h3>
                  <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-1">Comparativo Fiscal Monte & Chaisa</p>
                </div>
                <div className="p-4 bg-indigo-50 text-indigo-600 rounded-2xl"><TrendingUp size={24} /></div>
             </div>
             <div className="h-[350px] w-full">
                <ResponsiveContainer width="100%" height="100%" minWidth={0} minHeight={0}>
                   <BarChart data={[{ name: 'Global', receita: stats.revenue, despesa: stats.expenses }]}>
                      <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                      <XAxis dataKey="name" hide />
                      <YAxis hide />
                      <Tooltip 
                        contentStyle={{ borderRadius: '2rem', border: 'none', boxShadow: '0 25px 50px rgba(0,0,0,0.1)', padding: '1.5rem' }} 
                        itemStyle={{ fontWeight: 900, textTransform: 'uppercase', fontSize: '10px' }}
                      />
                      <Bar dataKey="receita" fill="#6366f1" radius={[15, 15, 0, 0]} barSize={80} />
                      <Bar dataKey="despesa" fill="#f43f5e" radius={[15, 15, 0, 0]} barSize={80} />
                   </BarChart>
                </ResponsiveContainer>
             </div>
          </div>
          <TodoList />
        </div>

        <div className="space-y-10">
           {/* Recent Contacts Widget - Insights Section */}
           <div className="bg-slate-900 rounded-[4rem] p-10 text-white shadow-2xl relative overflow-hidden border border-white/5">
              <div className="relative z-10">
                 <div className="flex items-center justify-between mb-10">
                    <div className="flex items-center gap-3">
                       <Bell size={20} className="text-indigo-400" />
                       <h3 className="text-lg font-black uppercase tracking-tight">Últimos 3 Contactos</h3>
                    </div>
                    <button onClick={fetchGlobalStats} className="p-2 bg-white/5 rounded-xl hover:bg-white/10 transition-all active:scale-95"><RefreshCw size={16}/></button>
                 </div>
                 <div className="space-y-6">
                    {recentMessages.length === 0 ? (
                      <p className="text-center text-xs text-slate-500 py-10">Sem mensagens novas.</p>
                    ) : recentMessages.map(msg => (
                      <div key={msg.id} className="group p-5 bg-white/5 rounded-3xl hover:bg-white/10 transition-all border border-transparent hover:border-white/5">
