          <span className="text-xl font-black text-white tracking-tighter leading-none">Monte<br/><span className="text-indigo-400">Imobiliária</span></span>
        </div>
        <button onClick={toggleSidebar} className="md:hidden text-slate-400 hover:text-white">
          <X size={24} />
        </button>
      </div>

      <nav className="flex-1 px-4 py-8 space-y-1.5 overflow-y-auto custom-scrollbar-dark">
        <div className="mb-6 px-4 text-[9px] font-black text-slate-600 uppercase tracking-[0.3em]">Ecossistema Monte Imobiliária</div>
        {filteredNav.map((item) => (
          <button
