                 </div>
                 <button className="w-full mt-10 py-5 bg-white text-slate-900 rounded-3xl text-[10px] font-black uppercase tracking-widest hover:bg-indigo-500 hover:text-white transition-all shadow-xl shadow-white/5">Ver Todas Mensagens</button>
