             </div>
           </div>
        </div>
      </div>

      {/* Monte AI Overlay Chat */}
      {aiChatOpen && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-slate-950/80 backdrop-blur-xl animate-in fade-in">
           <div className="bg-white rounded-[4rem] w-full max-w-2xl h-[80vh] flex flex-col shadow-2xl relative border-t-[12px] border-indigo-600">
              <button onClick={() => setAiChatOpen(false)} className="absolute top-8 right-8 p-3 bg-slate-50 text-slate-400 hover:text-slate-900 rounded-2xl transition-all"><CloseIcon size={24} /></button>

              <div className="p-10 border-b border-slate-50 flex items-center gap-4">
                 <div className="w-14 h-14 bg-indigo-600 rounded-2xl flex items-center justify-center text-white shadow-xl shadow-indigo-500/20">
                    <Bot size={32} />
                 </div>
                 <div>
                    <h3 className="text-2xl font-black text-slate-900 tracking-tight">Monte AI Assistant</h3>
                    <p className="text-[10px] font-black text-indigo-500 uppercase tracking-widest flex items-center gap-2">
                       <ShieldCheck size={12} /> Consultoria Monte Imobiliária Autorizada
                    </p>
                 </div>
              </div>

              <div className="flex-1 overflow-y-auto p-10 space-y-6 custom-scrollbar">
                 {chatMessages.map((msg, i) => (
                   <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                      <div className={`max-w-[85%] p-6 rounded-[2.5rem] text-sm font-medium shadow-sm leading-relaxed ${
                        msg.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none' : 'bg-slate-50 text-slate-700 rounded-tl-none border border-slate-100'
                      }`}>
                         {msg.text}
                      </div>
                   </div>
                 ))}
                 {isAiTyping && (
                   <div className="flex justify-start animate-pulse">
                      <div className="bg-slate-50 p-4 rounded-3xl rounded-tl-none flex gap-1.5 items-center border border-slate-100">
                         <div className="w-1.5 h-1.5 bg-indigo-600 rounded-full animate-bounce"></div>
                         <div className="w-1.5 h-1.5 bg-indigo-600 rounded-full animate-bounce [animation-delay:0.2s]"></div>
                         <div className="w-1.5 h-1.5 bg-indigo-600 rounded-full animate-bounce [animation-delay:0.4s]"></div>
                      </div>
                   </div>
                 )}
              </div>

              <div className="p-8 border-t border-slate-50">
                 <form onSubmit={handleSendToAI} className="flex gap-3">
                    <input 
                      autoFocus
                      value={chatInput}
                      onChange={e => setChatInput(e.target.value)}
                      placeholder="Pergunte sobre rentabilidade, equipe ou mercado da Monte Imobiliária..." 
                      className="flex-1 bg-slate-50 border-none rounded-3xl px-8 py-5 font-bold text-sm outline-none focus:ring-4 focus:ring-indigo-50"
                    />
                    <button type="submit" disabled={isAiTyping || !chatInput.trim()} className="px-8 py-5 bg-indigo-600 text-white rounded-3xl shadow-xl hover:bg-slate-900 transition-all active:scale-95 disabled:opacity-50">
                       <Send size={20} />
                    </button>
                 </form>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

