import PropertyDetailView from './views/PropertyDetailView';
import ServicesView from './views/ServicesView';
import ContactView from './views/ContactView';
import AboutView from './views/AboutView';
import CareerView from './views/CareerView';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [currentPath, setCurrentPath] = useState('home');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [selectedPropertyId, setSelectedPropertyId] = useState<string | null>(null);
  const [isInitializing, setIsInitializing] = useState(true);

  // IDENTIFICADOR DO ADMINISTRADOR GERAL (PROPRIETÁRIO)
  const ADMIN_GERAL_EMAIL = 'monteimobiliario@gmail.com';

  useEffect(() => {
    checkUser();

    // Escutar eventos de navegação interna do Dashboard (Hub Lateral)
    const handleInternalNav = (e: any) => {
      if (e.detail) setCurrentPath(e.detail);
    };
    window.addEventListener('navigate', handleInternalNav);

    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (event, session) => {
      if (session) {
        await fetchAndSetUser(session.user);
      } else {
        setCurrentUser(null);
        const erpPaths = ['dashboard', 'finance', 'hr', 'projects', 'plans', 'reports', 'admin', 'catalog', 'fleet', 'overview'];
        if (erpPaths.includes(currentPath)) {
          setCurrentPath('home');
        }
      }
    });
    return () => {
      subscription.unsubscribe();
      window.removeEventListener('navigate', handleInternalNav);
    };
  }, []);

  async function checkUser() {
    try {
      const { data: { session }, error } = await supabase.auth.getSession();
      if (error) throw error;
      if (session?.user) {
        await fetchAndSetUser(session.user);
      }
    } catch (err) {
      console.error("Initialization Error:", err);
    } finally {
      setIsInitializing(false);
    }
  }

  async function fetchAndSetUser(sbUser: any) {
    try {
      const { data: emp } = await supabase
        .from('employees')
        .select('*')
        .eq('email', sbUser.email)
        .maybeSingle();

      // LOGICA DE PODER ABSOLUTO PARA O ADMINISTRADOR GERAL
      const isOwner = sbUser.email === ADMIN_GERAL_EMAIL;

      const user: User = {
        id: sbUser.id,
        name: isOwner ? 'Administrador Geral' : (emp?.name || sbUser.email.split('@')[0]),
        email: sbUser.email,
        role: isOwner ? UserRole.ADMIN : (emp?.role || UserRole.EMPLOYEE),
        avatar: emp?.avatar || `https://picsum.photos/seed/${sbUser.id}/100`,
        permissions: isOwner 
          ? [
              'dashboard.view', 
              'catalog.view', 'catalog.manage', 
              'finance.view', 'finance.manage', 
              'projects.view', 'projects.manage', 
              'hr.view', 'hr.manage', 
              'fleet.view', 'fleet.manage', 
              'plans.view', 'plans.manage', 
              'admin.access', 'system.repair'
            ]
          : (emp?.permissions || [])
      };

      setCurrentUser(user);
      if (currentPath === 'login') setCurrentPath('dashboard');
    } catch (err) {
      console.error("Error profile sync:", err);
      setCurrentUser({
        id: sbUser.id,
        name: sbUser.email.split('@')[0],
        email: sbUser.email,
        role: UserRole.EMPLOYEE,
        avatar: `https://picsum.photos/seed/${sbUser.id}/100`,
        permissions: []
      });
    }
  }

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setCurrentUser(null);
    setCurrentPath('home');
  };

  const handleViewProperty = (id: string) => {
    setSelectedPropertyId(id);
    setCurrentPath('imovel-detalhes');
    window.scrollTo(0, 0);
  };

  const isERPRoute = ['dashboard', 'finance', 'hr', 'projects', 'plans', 'reports', 'admin', 'catalog', 'fleet', 'overview'].includes(currentPath);

  const renderContent = () => {
    switch (currentPath) {
      case 'home': return <HomeView onNavigate={setCurrentPath} onViewProperty={handleViewProperty} />;
      case 'imoveis': return <PropertyListView onViewProperty={handleViewProperty} />;
      case 'imovel-detalhes': return <PropertyDetailView propertyId={selectedPropertyId} onBack={() => setCurrentPath('imoveis')} />;
      case 'servicos': return <ServicesView />;
      case 'contato': return <ContactView />;
      case 'sobre': return <AboutView />;
      case 'carreira': return <CareerView />;
      case 'login': return (
        <LoginView 
          onLoginSuccess={(user) => {
            setCurrentUser(user);
            setCurrentPath('dashboard');
          }} 
          onBack={() => setCurrentPath('home')}
        />
      );
      case 'dashboard': return <DashboardView onNavigate={setCurrentPath} />;
      case 'catalog': return <CatalogView />;
      case 'finance': return <FinanceView />;
      case 'hr': return <HRView />;
      case 'fleet': return <FleetView />;
      case 'projects': return <ProjectsView />;
      case 'plans': return <PlansView />;
      case 'reports': return <ReportsView />;
      case 'overview': return <OverviewView />;
      case 'admin': return <AdminView currentUser={currentUser} />;
      default: return <HomeView onNavigate={setCurrentPath} onViewProperty={handleViewProperty} />;
    }
  };

  if (isInitializing) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-8 text-center">
        <div className="w-24 h-24 bg-slate-900 rounded-[3rem] flex items-center justify-center p-5 shadow-2xl animate-pulse mb-8">
          <img src="https://i.ibb.co/LzfNdf7Y/building-logo.png" className="w-full h-full object-contain brightness-0 invert" alt="Loading" />
        </div>
        <h2 className="text-xl font-black text-slate-900 animate-pulse uppercase tracking-[0.3em]">Acedendo à Infraestrutura Monte...</h2>
      </div>
    );
  }

  if (isERPRoute && currentUser) {
    return (
      <div className="flex h-screen overflow-hidden bg-slate-50">
        <Sidebar 
          currentPath={currentPath} 
          onNavigate={setCurrentPath} 
          user={currentUser}
          isOpen={isSidebarOpen}
          toggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)}
        />
        <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
          <Header 
            user={currentUser} 
            onLogout={handleLogout} 
            onOpenSidebar={() => setIsSidebarOpen(true)} 
            onViewProperty={handleViewProperty}
          />
          <main className="flex-1 overflow-y-auto p-4 md:p-10">
            <div className="max-w-[1600px] mx-auto">{renderContent()}</div>
          </main>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-white flex flex-col">
      <Navbar currentPath={currentPath} onNavigate={setCurrentPath} isLoggedIn={!!currentUser} />
      <main className="flex-1">
        {renderContent()}
      </main>
      <Footer onNavigate={setCurrentPath} />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  TrendingUp, Users, Home, 
  MessageSquare, Wallet, 
  Sparkles, X as CloseIcon, 
  ShieldCheck, Send, Bot, RefreshCw,
  Briefcase, ArrowRight, Bell,
  Truck, LayoutTemplate,
  ChevronRight,
  Shield,
  Settings2,
  BarChart3
} from 'lucide-react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, 
  ResponsiveContainer
} from 'recharts';
import { supabase } from '../supabaseClient';
import { getStrategicInsight, chatWithMonteAI } from '../geminiService';
import TodoList from '../components/TodoList';

const DashboardView: React.FC = () => {
  const [stats, setStats] = useState({ 
    revenue: 0, 
    expenses: 0, 
    employees: 0, 
    properties: 0, 
    contacts: 0,
    pendingApps: 0 
  });
  const [recentMessages, setRecentMessages] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [aiInsight, setAiInsight] = useState<string>('Sincronizando comando central...');

  const [aiChatOpen, setAiChatOpen] = useState(false);
  const [chatInput, setChatInput] = useState('');
  const [chatMessages, setChatMessages] = useState<{role: 'user' | 'ai', text: string}[]>([
    { role: 'ai', text: 'Saudações, Administrador Geral. O ecossistema Monte Imobiliária está 100% operacional. Qual setor deseja comandar?' }
  ]);
  const [isAiTyping, setIsAiTyping] = useState(false);

  useEffect(() => {
    fetchGlobalStats();
  }, []);

  async function fetchGlobalStats() {
    setLoading(true);
    try {
      const [txRes, empRes, propRes, contactRes, msgListRes, appCountRes] = await Promise.all([
        supabase.from('transactions').select('*'),
        supabase.from('employees').select('*', { count: 'exact', head: true }),
        supabase.from('properties').select('*', { count: 'exact', head: true }),
        supabase.from('contact_requests').select('*', { count: 'exact', head: true }),
        supabase.from('contact_requests').select('*').order('created_at', { ascending: false }).limit(3),
        supabase.from('job_applications').select('*', { count: 'exact', head: true }).eq('status', 'Pendente')
      ]);

      const txs = txRes.data || [];
      const rev = txs.filter(t => t.type === 'RECEITA').reduce((a, b) => a + Number(b.amount || 0), 0);
      const exp = txs.filter(t => t.type === 'DESPESA').reduce((a, b) => a + Number(b.amount || 0), 0);

      const newStats = {
        revenue: rev, 
        expenses: exp,
        employees: empRes.count || 0,
        properties: propRes.count || 0, 
        contacts: contactRes.count || 0,
        pendingApps: appCountRes.count || 0
      };
      setStats(newStats);
      setRecentMessages(msgListRes.data || []);

      const insight = await getStrategicInsight(`Saldo: ${rev-exp}MT, Staff: ${empRes.count}, Leads: ${contactRes.count}`);
      setAiInsight(insight);
    } catch (error: any) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  }

  const handleSendToAI = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!chatInput.trim() || isAiTyping) return;
    const userMsg = chatInput;
    setChatMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setChatInput('');
    setIsAiTyping(true);
    const response = await chatWithMonteAI(userMsg, stats);
    setChatMessages(prev => [...prev, { role: 'ai', text: response }]);
    setIsAiTyping(false);
  };

  const chartData = useMemo(() => [
    { name: 'Fluxo', receita: stats.revenue, despesa: stats.expenses }
  ], [stats]);

  if (loading) return (
    <div className="h-full flex flex-col items-center justify-center py-32 gap-6 bg-slate-50">
      <div className="w-20 h-20 bg-slate-900 rounded-[2.5rem] flex items-center justify-center p-4 shadow-2xl animate-bounce">
         <img src="https://i.ibb.co/LzfNdf7Y/building-logo.png" className="w-full h-full object-contain brightness-0 invert" alt="Monte Logo" />
      </div>
      <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.5em] animate-pulse">Iniciando Centro de Comando...</p>
    </div>
  );

  return (
    <div className="space-y-10 animate-in fade-in duration-700 pb-20">

      {/* GRID PRINCIPAL: MENU À ESQUERDA | VISÃO À DIREITA */}
      <div className="grid grid-cols-1 xl:grid-cols-12 gap-8 items-start">

        {/* LADO ESQUERDO: MASTER HUB (MENU DE COMANDO INTEGRADO) */}
        <div className="xl:col-span-4 space-y-6">
           <div className="bg-slate-950 rounded-[4rem] p-10 text-white shadow-[0_40px_100px_rgba(0,0,0,0.4)] relative overflow-hidden border border-white/5">
              <div className="absolute top-0 right-0 w-80 h-80 bg-indigo-600/10 rounded-full blur-[120px] -translate-y-1/2 translate-x-1/2"></div>

              {/* Branding Section */}
              <div className="relative z-10 mb-12 flex items-center gap-5">
                 <div className="w-16 h-16 bg-white/10 rounded-[2rem] p-3 backdrop-blur-xl border border-white/10 flex items-center justify-center">
                    <img src="https://i.ibb.co/LzfNdf7Y/building-logo.png" className="w-full h-full object-contain brightness-0 invert" alt="Logo" />
                 </div>
                 <div>
                    <h2 className="text-3xl font-black tracking-tighter uppercase leading-none">Monte<br/><span className="text-indigo-500">Imobiliária</span></h2>
                    <div className="flex items-center gap-2 mt-2 px-3 py-1 bg-indigo-500/20 rounded-full border border-indigo-500/20 w-fit">
                       <Shield size={10} className="text-indigo-400" />
                       <span className="text-[9px] font-black uppercase tracking-widest text-indigo-400">Administrador Geral</span>
                    </div>
                 </div>
              </div>

              {/* Menu de Funções Master */}
              <div className="space-y-3 relative z-10">
                 {[
                   { label: 'Finanças', path: 'finance', icon: <Wallet size={20} />, color: 'hover:bg-emerald-600', val: `${(stats.revenue/1000).toFixed(0)}k MT`, colorTag: 'text-emerald-400' },
                   { label: 'RH & Staff', path: 'hr', icon: <Users size={20} />, color: 'hover:bg-blue-600', val: `${stats.employees} Colaboradores`, colorTag: 'text-blue-400' },
                   { label: 'Catálogo', path: 'catalog', icon: <LayoutTemplate size={20} />, color: 'hover:bg-indigo-600', val: `${stats.properties} Ativos`, colorTag: 'text-indigo-400' },
                   { label: 'Projetos', path: 'projects', icon: <Briefcase size={20} />, color: 'hover:bg-amber-600', val: 'Gestão de Obras', colorTag: 'text-amber-400' },
                   { label: 'Frota', path: 'fleet', icon: <Truck size={20} />, color: 'hover:bg-rose-600', val: 'Veículos & Logística', colorTag: 'text-rose-400' },
                   { label: 'Sistemas', path: 'admin', icon: <Settings2 size={20} />, color: 'hover:bg-purple-600', val: 'Privilégios Cloud', colorTag: 'text-purple-400' },
                 ].map((item, i) => (
                   <button 
                     key={i} 
                     onClick={() => window.dispatchEvent(new CustomEvent('navigate', { detail: item.path }))}
                     className={`w-full flex items-center justify-between p-6 bg-white/5 border border-white/5 rounded-[2rem] transition-all group/btn ${item.color} active:scale-[0.98] shadow-sm`}
                   >
