                      <ChevronRight size={18} className="text-white/20 group-hover/btn:text-white group-hover/btn:translate-x-1 transition-all" />
                   </button>
                 ))}
              </div>

              <div className="mt-12 pt-8 border-t border-white/5 flex items-center justify-between opacity-60">
                 <div className="flex items-center gap-2">
                    <div className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse"></div>
                    <span className="text-[10px] font-black uppercase tracking-widest">Sincronizado</span>
