                 <h3 className="text-xs font-black uppercase tracking-widest text-slate-400 flex items-center gap-2"><Bell size={14} /> Inbox Recente</h3>
              </div>
              <div className="space-y-4">
                 {recentMessages.map((msg, i) => (
                   <div key={i} className="flex items-center gap-4 group cursor-default">
                      <div className="w-10 h-10 bg-slate-50 text-slate-400 rounded-xl flex items-center justify-center font-black group-hover:bg-indigo-600 group-hover:text-white transition-all">{msg.name.charAt(0)}</div>
                      <div className="min-w-0 flex-1">
                         <p className="text-xs font-black text-slate-900 truncate">{msg.name}</p>
