                    <Bot size={32} />
                 </div>
                 <div>
                    <p className="text-[10px] font-black text-indigo-500 uppercase tracking-[0.3em] mb-1 flex items-center gap-2">
                       <Sparkles size={12} className="animate-pulse" /> Monte Strategic Advisor
                    </p>
                    <h2 className="text-xl font-black text-slate-900 tracking-tight leading-tight italic">"{aiInsight}"</h2>
