              <button onClick={() => setAiChatOpen(true)} className="px-8 py-4 bg-indigo-600 text-white rounded-[1.5rem] text-[10px] font-black uppercase tracking-widest hover:bg-slate-900 transition-all shadow-xl shadow-indigo-600/20 whitespace-nowrap">Consultar IA</button>
