                 <div>
                    <h3 className="text-2xl font-black text-slate-900 tracking-tight leading-none mb-1">Monte Strategic Advisor</h3>
                    <p className="text-[10px] font-black text-indigo-500 uppercase tracking-widest flex items-center gap-2"><ShieldCheck size={12} /> Comandos Administrativos Ativos</p>
