              <div className="flex-1 overflow-y-auto p-10 space-y-6 custom-scrollbar bg-slate-50/30">
                 {chatMessages.map((msg, i) => (
                   <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                      <div className={`max-w-[85%] p-6 rounded-[2.5rem] text-sm font-medium shadow-sm leading-relaxed ${
                        msg.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none shadow-indigo-200' : 'bg-white text-slate-700 rounded-tl-none border border-slate-100'
                      }`}>
                         {msg.text}
                      </div>
                   </div>
                 ))}
                 {isAiTyping && (
