              </div>

              <div className="p-8 border-t border-slate-50">
                 <form onSubmit={handleSendToAI} className="flex gap-3">
                    <input autoFocus value={chatInput} onChange={e => setChatInput(e.target.value)} placeholder="Comande a visão estratégica aqui..." className="flex-1 bg-slate-50 border-none rounded-3xl px-8 py-5 font-bold text-sm outline-none focus:ring-4 focus:ring-indigo-50 shadow-inner" />
                    <button type="submit" disabled={isAiTyping || !chatInput.trim()} className="px-8 py-5 bg-indigo-600 text-white rounded-3xl shadow-xl hover:bg-slate-900 transition-all active:scale-95 disabled:opacity-50">
                       <Send size={20} />
                    </button>
                 </form>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

