import React, { useState, useEffect } from 'react';
import { 
  X, Wallet, Users, LayoutTemplate, Briefcase, Truck, Settings2, 
  Layers, RefreshCw, ChevronRight, Activity
} from 'lucide-react';
import { supabase } from '../supabaseClient';
import { User } from '../types';

interface SidebarProps {
  currentPath: string;
  onNavigate: (path: string) => void;
  user: User;
  isOpen: boolean;
  toggleSidebar: () => void;
}

const Sidebar: React.FC<SidebarProps> = ({ currentPath, onNavigate, user, isOpen, toggleSidebar }) => {
  const [stats, setStats] = useState({ revenue: 0, employees: 0, properties: 0 });

  useEffect(() => {
    fetchMiniStats();
  }, []);

  async function fetchMiniStats() {
    try {
      const [txRes, empRes, propRes] = await Promise.all([
        supabase.from('transactions').select('amount').eq('type', 'RECEITA'),
        supabase.from('employees').select('*', { count: 'exact', head: true }),
        supabase.from('properties').select('*', { count: 'exact', head: true })
      ]);
      const rev = (txRes.data || []).reduce((a, b) => a + Number(b.amount || 0), 0);
      setStats({
        revenue: rev,
        employees: empRes.count || 0,
        properties: propRes.count || 0
      });
    } catch (e) {}
  }

  const hubItems = [
    { label: 'Fluxo Financeiro', sub: 'Cash', val: `${(stats.revenue/1000).toFixed(0)}k`, path: 'finance', icon: <Wallet size={18} />, activeColor: 'bg-emerald-500' },
    { label: 'Gestão Staff', sub: 'Ativos', val: stats.employees.toString(), path: 'hr', icon: <Users size={18} />, activeColor: 'bg-blue-500' },
    { label: 'Catálogo Ativo', sub: 'Unid.', val: stats.properties.toString(), path: 'catalog', icon: <LayoutTemplate size={18} />, activeColor: 'bg-indigo-500' },
    { label: 'Obras & Projetos', sub: 'Build', val: 'V14', path: 'projects', icon: <Briefcase size={18} />, activeColor: 'bg-amber-500' },
    { label: 'Operações Frota', sub: 'On', val: 'Logistics', path: 'fleet', icon: <Truck size={18} />, activeColor: 'bg-rose-500' },
    { label: 'Configurações', sub: 'System', val: 'v15', path: 'admin', icon: <Settings2 size={18} />, activeColor: 'bg-purple-500' },
  ];

  return (
    <aside className={`fixed inset-y-0 left-0 z-50 transform ${isOpen ? 'translate-x-0' : '-translate-x-full'} md:relative md:translate-x-0 transition-all duration-500 ease-in-out w-80 p-6 flex flex-col`}>
      {/* Floating Glass Container */}
      <div className="flex-1 bg-slate-950/95 backdrop-blur-2xl rounded-[3.5rem] border border-white/10 shadow-[20px_0_60px_rgba(0,0,0,0.4)] flex flex-col overflow-hidden relative">
        <div className="absolute inset-0 opacity-[0.03] pointer-events-none" style={{ backgroundImage: 'radial-gradient(#fff 1px, transparent 1px)', backgroundSize: '24px 24px' }}></div>

        {/* Header Logo */}
        <div className="p-8 border-b border-white/5 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-gradient-to-tr from-indigo-600 to-blue-500 rounded-[1.2rem] flex items-center justify-center p-2.5 shadow-xl shadow-indigo-500/20">
              <img src="https://i.ibb.co/LzfNdf7Y/building-logo.png" className="w-full h-full object-contain brightness-0 invert" alt="Logo" />
            </div>
            <div>
              <h2 className="text-2xl font-black text-white tracking-tighter leading-none">Monte<br/><span className="text-indigo-400">Hub</span></h2>
            </div>
          </div>
          <button onClick={toggleSidebar} className="md:hidden text-slate-500 hover:text-white"><X size={24} /></button>
        </div>

        {/* Navigation */}
        <nav className="flex-1 px-4 py-8 space-y-3 overflow-y-auto custom-scrollbar-dark relative z-10">
          <div className="mb-6 px-4 flex items-center justify-between">
            <span className="text-[9px] font-black text-slate-500 uppercase tracking-[0.3em]">Ecossistema Monte</span>
            <RefreshCw size={12} className="text-slate-600 cursor-pointer hover:text-indigo-400 transition-all" onClick={fetchMiniStats} />
          </div>

          {hubItems.map((item) => {
            const isActive = currentPath === item.path;
            return (
              <button
                key={item.path}
                onClick={() => {
                  onNavigate(item.path);
                  if (window.innerWidth < 768) toggleSidebar();
                }}
                className={`w-full group flex items-center justify-between p-4 rounded-[2rem] transition-all duration-300 border ${
                  isActive 
                  ? 'bg-white/10 border-white/10 shadow-2xl scale-[1.02]' 
                  : 'hover:bg-white/5 border-transparent hover:border-white/5'
                }`}
              >
                <div className="flex items-center gap-4">
                  <div className={`w-11 h-11 rounded-2xl flex items-center justify-center transition-all duration-500 ${
                    isActive ? item.activeColor + ' text-white shadow-lg' : 'bg-white/5 text-slate-500 group-hover:text-slate-300'
                  }`}>
                    {item.icon}
                  </div>
                  <div className="text-left">
                    <span className={`block text-[11px] font-black uppercase tracking-widest leading-none mb-1 ${isActive ? 'text-white' : 'text-slate-400'}`}>{item.label}</span>
                    <span className="text-[9px] font-bold text-slate-600 uppercase group-hover:text-slate-500 transition-colors">{item.sub}</span>
