                  <ChevronRight size={14} className={`transition-all ${isActive ? 'text-white opacity-100' : 'opacity-0'}`} />
                </div>
              </button>
            );
          })}
        </nav>

        {/* Footer Status Section */}
        <div className="p-6 bg-black/40 mt-auto border-t border-white/5">
          <div className="bg-white/5 rounded-[2rem] p-5 border border-white/5 flex flex-col gap-4">
             <div className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                   <div className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse shadow-[0_0_10px_#10b981]"></div>
                   <span className="text-[10px] font-black text-emerald-400 uppercase tracking-widest">Sincronizado</span>
                </div>
                <Activity size={14} className="text-slate-600" />
             </div>
             <div className="flex items-center gap-3">
                <img src={user.avatar} className="w-8 h-8 rounded-xl object-cover ring-1 ring-white/20" alt="User" />
                <div className="min-w-0">
                   <p className="text-[10px] font-black text-white truncate leading-none mb-1">{user.name}</p>
                   <p className="text-[8px] font-bold text-slate-500 uppercase truncate">{user.role}</p>
                </div>
             </div>
          </div>
        </div>
      </div>
    </aside>
  );
};

