import React, { useState, useEffect, useMemo } from 'react';
import { 
  TrendingUp, Users, Home, 
  Wallet, Sparkles, X as CloseIcon, 
  ShieldCheck, Send, Bot, RefreshCw,
  Briefcase, ArrowRight, Bell,
  Truck, LayoutTemplate,
  ChevronRight,
  Shield,
  Settings2,
  Zap,
  Activity,
  ArrowUpRight,
  Target
} from 'lucide-react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, 
  ResponsiveContainer
} from 'recharts';
import { supabase } from '../supabaseClient';
import { getStrategicInsight, chatWithMonteAI } from '../geminiService';
import TodoList from '../components/TodoList';

const DashboardView: React.FC = () => {
  const [stats, setStats] = useState({ 
    revenue: 0, 
    expenses: 0, 
    employees: 0, 
    properties: 0, 
    contacts: 0,
    pendingApps: 0 
  });
  const [recentMessages, setRecentMessages] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [aiInsight, setAiInsight] = useState<string>('Analizando rede neural da Monte...');

  const [aiChatOpen, setAiChatOpen] = useState(false);
  const [chatInput, setChatInput] = useState('');
  const [chatMessages, setChatMessages] = useState<{role: 'user' | 'ai', text: string}[]>([
    { role: 'ai', text: 'Central Monte Imobiliária Ativa. Aguardando comandos estratégicos.' }
  ]);
  const [isAiTyping, setIsAiTyping] = useState(false);

  useEffect(() => {
    fetchGlobalStats();
  }, []);

  async function fetchGlobalStats() {
    setLoading(true);
    try {
      const [txRes, empRes, propRes, contactRes, msgListRes, appCountRes] = await Promise.all([
        supabase.from('transactions').select('*'),
        supabase.from('employees').select('*', { count: 'exact', head: true }),
        supabase.from('properties').select('*', { count: 'exact', head: true }),
        supabase.from('contact_requests').select('*', { count: 'exact', head: true }),
        supabase.from('contact_requests').select('*').order('created_at', { ascending: false }).limit(3),
        supabase.from('job_applications').select('*', { count: 'exact', head: true }).eq('status', 'Pendente')
      ]);

      const txs = txRes.data || [];
      const rev = txs.filter(t => t.type === 'RECEITA').reduce((a, b) => a + Number(b.amount || 0), 0);
      const exp = txs.filter(t => t.type === 'DESPESA').reduce((a, b) => a + Number(b.amount || 0), 0);

      const newStats = {
        revenue: rev, 
        expenses: exp,
        employees: empRes.count || 0,
        properties: propRes.count || 0, 
        contacts: contactRes.count || 0,
        pendingApps: appCountRes.count || 0
      };
      setStats(newStats);
      setRecentMessages(msgListRes.data || []);

      const insight = await getStrategicInsight(`Saldo: ${rev-exp}MT, Staff: ${empRes.count}, Leads: ${contactRes.count}`);
      setAiInsight(insight);
    } catch (error: any) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  }

  const handleSendToAI = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!chatInput.trim() || isAiTyping) return;
    const userMsg = chatInput;
    setChatMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setChatInput('');
    setIsAiTyping(true);
    const response = await chatWithMonteAI(userMsg, stats);
    setChatMessages(prev => [...prev, { role: 'ai', text: response }]);
    setIsAiTyping(false);
  };

  const chartData = useMemo(() => [
    { name: 'Jan', receita: stats.revenue * 0.75, despesa: stats.expenses * 0.8 },
    { name: 'Fev', receita: stats.revenue * 0.9, despesa: stats.expenses * 0.85 },
    { name: 'Mar', receita: stats.revenue, despesa: stats.expenses }
  ], [stats]);

  if (loading) return (
    <div className="h-[70vh] flex flex-col items-center justify-center gap-6">
      <div className="w-20 h-20 bg-slate-900 rounded-[2.5rem] flex items-center justify-center p-4 shadow-2xl animate-pulse ring-4 ring-indigo-500/20">
         <img src="https://i.ibb.co/LzfNdf7Y/building-logo.png" className="w-full h-full object-contain brightness-0 invert" alt="Loading" />
      </div>
      <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.8em] animate-pulse">Iniciando Ecossistema v15</p>
    </div>
  );

  return (
    <div className="space-y-10 animate-in fade-in duration-1000 pb-20">

      {/* SECTION 1: IA EXECUTIVE BANNER - O Cérebro do Sistema */}
      <div className="relative group">
        <div className="absolute -inset-1 bg-gradient-to-r from-indigo-600/30 to-blue-600/30 rounded-[3rem] blur-2xl opacity-50 group-hover:opacity-100 transition duration-1000"></div>
        <div className="relative bg-white rounded-[3rem] border border-slate-100 p-10 flex flex-col lg:flex-row items-center justify-between gap-10 shadow-2xl overflow-hidden">
           {/* Widget Pattern */}
           <div className="absolute inset-0 opacity-[0.03] pointer-events-none" style={{ backgroundImage: 'radial-gradient(#000 1px, transparent 1px)', backgroundSize: '20px 20px' }}></div>

           <div className="flex items-center gap-8 relative z-10">
              <div className="relative shrink-0">
                 <div className="w-20 h-20 bg-slate-950 rounded-[2rem] flex items-center justify-center shadow-2xl rotate-3 group-hover:rotate-0 transition-all duration-500">
                    <Bot size={44} className="text-indigo-400" />
                 </div>
                 <div className="absolute -top-2 -right-2 w-6 h-6 bg-emerald-500 border-4 border-white rounded-full animate-bounce"></div>
              </div>
              <div className="space-y-2">
                 <div className="flex items-center gap-2">
                    <span className="text-[10px] font-black text-indigo-600 uppercase tracking-[0.4em] bg-indigo-50 px-4 py-1.5 rounded-full">Monte Intel Core v15</span>
                    <Sparkles size={14} className="text-indigo-400 animate-pulse" />
                 </div>
                 <h2 className="text-2xl md:text-3xl font-black text-slate-900 tracking-tighter italic leading-tight">
                    "{aiInsight}"
                 </h2>
              </div>
           </div>

           <button onClick={() => setAiChatOpen(true)} className="px-12 py-5 bg-slate-950 text-white rounded-[2rem] font-black text-[10px] uppercase tracking-widest hover:bg-indigo-600 transition-all shadow-2xl flex items-center gap-4 group/btn whitespace-nowrap active:scale-95">
              Consultar IA Central <ArrowUpRight size={18} className="group-hover/btn:translate-x-1 group-hover/btn:-translate-y-1 transition-transform" />
           </button>
        </div>
      </div>

      {/* SECTION 2: PULSE METRICS - Os Indicadores Vitais */}
