  const hubItems = [
    { label: 'Fluxo Financeiro', sub: 'Cash', val: `${(stats.revenue/1000).toFixed(0)}k`, path: 'finance', icon: <Wallet size={18} />, activeColor: 'bg-emerald-500' },
