            <div className="flex items-center gap-4">
              <div className="w-12 h-12 bg-gradient-to-tr from-indigo-600 to-blue-500 rounded-[1.2rem] flex items-center justify-center p-2.5 shadow-2xl shadow-indigo-500/20">
