import React, { useState, useEffect } from 'react';
import { UserRole, User } from './types';
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import Navbar from './components/Navbar';
import Footer from './components/Footer';
import { supabase } from './supabaseClient';

// ERP Views
import DashboardView from './views/DashboardView';
import FinanceView from './views/FinanceView';
import HRView from './views/HRView';
import ProjectsView from './views/ProjectsView';
import PlansView from './views/PlansView';
import ReportsView from './views/ReportsView';
import AdminView from './views/AdminView';
import CatalogView from './views/CatalogView';
import FleetView from './views/FleetView';
import LoginView from './views/LoginView';
import OverviewView from './views/OverviewView';

// Public Views
import HomeView from './views/HomeView';
import PropertyListView from './views/PropertyListView';
import PropertyDetailView from './views/PropertyDetailView';
import ServicesView from './views/ServicesView';
import ContactView from './views/ContactView';
import AboutView from './views/AboutView';
import CareerView from './views/CareerView';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [currentPath, setCurrentPath] = useState('home');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [selectedPropertyId, setSelectedPropertyId] = useState<string | null>(null);
  const [isInitializing, setIsInitializing] = useState(true);
  const [isDarkMode, setIsDarkMode] = useState(() => {
    const saved = localStorage.getItem('monte_theme');
    return saved === 'dark' || (!saved && window.matchMedia('(prefers-color-scheme: dark)').matches);
  });

  const ADMIN_GERAL_EMAIL = 'monteimobiliario@gmail.com';

  useEffect(() => {
    localStorage.setItem('monte_theme', isDarkMode ? 'dark' : 'light');
    if (isDarkMode) document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, [isDarkMode]);

  useEffect(() => {
    checkUser();
    const handleInternalNav = (e: any) => { if (e.detail) setCurrentPath(e.detail); };
    window.addEventListener('navigate', handleInternalNav);

    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (event, session) => {
      if (session) {
        await fetchAndSetUser(session.user);
      } else {
        setCurrentUser(null);
        const erpPaths = ['dashboard', 'finance', 'hr', 'projects', 'plans', 'reports', 'admin', 'catalog', 'fleet', 'overview'];
        if (erpPaths.includes(currentPath)) setCurrentPath('home');
      }
    });
    return () => {
      subscription.unsubscribe();
      window.removeEventListener('navigate', handleInternalNav);
    };
  }, []);

  async function checkUser() {
    try {
      const { data: { session } } = await supabase.auth.getSession();
      if (session?.user) await fetchAndSetUser(session.user);
    } catch (err) {} finally { setIsInitializing(false); }
  }

  async function fetchAndSetUser(sbUser: any) {
    try {
      const { data: emp } = await supabase.from('employees').select('*').eq('email', sbUser.email).maybeSingle();
      const isOwner = sbUser.email === ADMIN_GERAL_EMAIL;
      const user: User = {
        id: sbUser.id,
        name: isOwner ? 'Administrador Geral' : (emp?.name || sbUser.email.split('@')[0]),
        email: sbUser.email,
        role: isOwner ? UserRole.ADMIN : (emp?.role || UserRole.EMPLOYEE),
        avatar: emp?.avatar || `https://picsum.photos/seed/${sbUser.id}/100`,
        permissions: isOwner ? ['dashboard.view', 'catalog.view', 'catalog.manage', 'finance.view', 'finance.manage', 'projects.view', 'projects.manage', 'hr.view', 'hr.manage', 'fleet.view', 'fleet.manage', 'plans.view', 'plans.manage', 'admin.access', 'system.repair'] : (emp?.permissions || [])
      };
      setCurrentUser(user);
      if (currentPath === 'login') setCurrentPath('dashboard');
    } catch (err) {
      setCurrentUser({ id: sbUser.id, name: sbUser.email.split('@')[0], email: sbUser.email, role: UserRole.EMPLOYEE, avatar: `https://picsum.photos/seed/${sbUser.id}/100`, permissions: [] });
    }
  }

  const handleLogout = async () => { await supabase.auth.signOut(); setCurrentUser(null); setCurrentPath('home'); };

  const handleViewProperty = (id: string) => { setSelectedPropertyId(id); setCurrentPath('imovel-detalhes'); window.scrollTo(0, 0); };

  const isERPRoute = ['dashboard', 'finance', 'hr', 'projects', 'plans', 'reports', 'admin', 'catalog', 'fleet', 'overview'].includes(currentPath);

  const renderContent = () => {
    switch (currentPath) {
      case 'home': return <HomeView onNavigate={setCurrentPath} onViewProperty={handleViewProperty} />;
      case 'imoveis': return <PropertyListView onViewProperty={handleViewProperty} />;
      case 'imovel-detalhes': return <PropertyDetailView propertyId={selectedPropertyId} onBack={() => setCurrentPath('imoveis')} />;
      case 'servicos': return <ServicesView />;
      case 'contato': return <ContactView />;
      case 'sobre': return <AboutView />;
      case 'carreira': return <CareerView />;
      case 'login': return <LoginView onLoginSuccess={(u) => { setCurrentUser(u); setCurrentPath('dashboard'); }} onBack={() => setCurrentPath('home')} />;
      case 'dashboard': return <DashboardView />;
      case 'catalog': return <CatalogView />;
      case 'finance': return <FinanceView />;
      case 'hr': return <HRView />;
      case 'fleet': return <FleetView />;
      case 'projects': return <ProjectsView />;
      case 'plans': return <PlansView />;
      case 'reports': return <ReportsView />;
      case 'overview': return <OverviewView />;
      case 'admin': return <AdminView currentUser={currentUser} />;
      default: return <HomeView onNavigate={setCurrentPath} onViewProperty={handleViewProperty} />;
    }
  };

  if (isInitializing) {
    return (
      <div className="min-h-screen bg-slate-950 flex flex-col items-center justify-center p-8 text-center">
        <div className="w-20 h-20 bg-indigo-600 rounded-[2.5rem] flex items-center justify-center p-4 shadow-[0_0_50px_rgba(79,70,229,0.4)] animate-pulse mb-8">
          <img src="https://i.ibb.co/LzfNdf7Y/building-logo.png" className="w-full h-full object-contain brightness-0 invert" alt="Loading" />
        </div>
        <h2 className="text-sm font-black text-indigo-400 animate-pulse uppercase tracking-[0.5em]">Acedendo à Infraestrutura Monte...</h2>
      </div>
    );
  }

  if (isERPRoute && currentUser) {
    return (
      <div className={`flex h-screen overflow-hidden transition-colors duration-500 ${isDarkMode ? 'bg-slate-950' : 'bg-slate-50'} relative`}>
        <Sidebar currentPath={currentPath} onNavigate={setCurrentPath} user={currentUser} isOpen={isSidebarOpen} toggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)} />
        <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
          <Header 
            user={currentUser} 
            onLogout={handleLogout} 
            onOpenSidebar={() => setIsSidebarOpen(true)} 
            onViewProperty={handleViewProperty}
            isDarkMode={isDarkMode}
            onToggleTheme={() => setIsDarkMode(!isDarkMode)}
          />
          <main className="flex-1 overflow-y-auto p-6 md:p-14 custom-scrollbar">
            <div className="max-w-[1600px] mx-auto">{renderContent()}</div>
          </main>
        </div>
      </div>
    );
  }

  return (
    <div className={`min-h-screen flex flex-col transition-colors duration-500 ${isDarkMode ? 'bg-slate-950 text-white' : 'bg-white text-slate-900'}`}>
      <Navbar currentPath={currentPath} onNavigate={setCurrentPath} isLoggedIn={!!currentUser} />
      <main className="flex-1">{renderContent()}</main>
      <Footer onNavigate={setCurrentPath} />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { User, Property, UserRole } from '../types';
import { Bell, Search, LogOut, Menu, Loader2, Home, MapPin, ChevronRight, X, Sparkles, Building2, BellRing, Sun, Moon } from 'lucide-react';
import { supabase } from '../supabaseClient';

interface HeaderProps {
  user: User;
  onLogout: () => void;
  onOpenSidebar: () => void;
  onViewProperty: (id: string) => void;
  isDarkMode?: boolean;
  onToggleTheme?: () => void;
}

const NOTIFICATION_SOUND = 'https://assets.mixkit.co/active_storage/sfx/2869/2869-preview.mp3';

const Header: React.FC<HeaderProps> = ({ user, onLogout, onOpenSidebar, onViewProperty, isDarkMode, onToggleTheme }) => {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<Property[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [showResults, setShowResults] = useState(false);
  const [unreadApplications, setUnreadApplications] = useState(0);
  const [showNotificationPopup, setShowNotificationPopup] = useState(false);
  const [showPropertyNotification, setShowPropertyNotification] = useState(false);
  const [lastAddedProperty, setLastAddedProperty] = useState<Property | null>(null);
  const searchRef = useRef<HTMLDivElement>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  useEffect(() => {
    audioRef.current = new Audio(NOTIFICATION_SOUND);
    fetchInitialUnread();

    const channel = supabase
      .channel('header_notifications')
      .on('postgres_changes', { event: 'INSERT', table: 'job_applications' }, () => {
        setUnreadApplications(prev => prev + 1);
        setShowNotificationPopup(true);
        if (audioRef.current) audioRef.current.play().catch(() => {});
        setTimeout(() => setShowNotificationPopup(false), 5000);
      })
      .on('postgres_changes', { event: 'INSERT', table: 'properties' }, (payload) => {
        const adminRoles = [UserRole.ADMIN, UserRole.CEO, UserRole.MANAGER];
        if (adminRoles.includes(user.role)) {
          setLastAddedProperty(payload.new as Property);
          setShowPropertyNotification(true);
          if (audioRef.current) audioRef.current.play().catch(() => {});
          setTimeout(() => setShowPropertyNotification(false), 8000);
        }
      })
      .on('postgres_changes', { event: 'UPDATE', table: 'job_applications' }, () => {
        fetchInitialUnread();
      })
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [user.role]);

  async function fetchInitialUnread() {
    const { count, error } = await supabase
      .from('job_applications')
      .select('*', { count: 'exact', head: true })
      .eq('status', 'Pendente');

    if (!error) setUnreadApplications(count || 0);
  }

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (searchRef.current && !searchRef.current.contains(event.target as Node)) {
        setShowResults(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  useEffect(() => {
    const timer = setTimeout(async () => {
      if (query.trim().length < 2) {
        setResults([]);
        setIsSearching(false);
        return;
      }

      setIsSearching(true);
      try {
        const { data, error } = await supabase
          .from('properties')
          .select('*')
          .or(`title.ilike.%${query}%,location.ilike.%${query}%`)
          .limit(5);

        if (!error && data) {
          setResults(data);
        }
      } catch (err) {
        console.error("Search error:", err);
      } finally {
        setIsSearching(false);
        setShowResults(true);
      }
    }, 400);

    return () => clearTimeout(timer);
  }, [query]);

  const handleSelectResult = (id: string) => {
    onViewProperty(id);
    setQuery('');
    setShowResults(false);
  };

  return (
    <header className={`h-20 border-b flex items-center justify-between px-4 md:px-8 shrink-0 relative z-[60] transition-colors duration-500 ${isDarkMode ? 'bg-slate-900 border-white/5' : 'bg-white border-slate-200'}`}>
      <div className="flex items-center gap-4 flex-1">
        <button onClick={onOpenSidebar} className="md:hidden text-slate-500 p-2 hover:bg-slate-100 rounded-lg">
          <Menu size={24} />
        </button>

        <div ref={searchRef} className="hidden sm:flex relative max-w-xs md:max-w-md w-full">
          <span className="absolute inset-y-0 left-3 flex items-center text-slate-400">
            {isSearching ? <Loader2 size={18} className="animate-spin text-blue-600" /> : <Search size={18} />}
          </span>
          <input
            type="text"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            onFocus={() => query.length >= 2 && setShowResults(true)}
            placeholder="Pesquisar catálogo..."
            className={`w-full pl-10 pr-10 py-2.5 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 border transition-all text-sm font-medium ${isDarkMode ? 'bg-slate-800 border-white/10 text-white' : 'bg-slate-50 border-slate-200 text-slate-900'}`}
          />
          {query && (
            <button 
              onClick={() => {setQuery(''); setResults([]);}} 
              className="absolute inset-y-0 right-3 flex items-center text-slate-400 hover:text-slate-600"
            >
              <X size={16} />
            </button>
          )}

          {showResults && (query.length >= 2) && (
            <div className={`absolute top-full left-0 right-0 mt-2 rounded-2xl shadow-2xl border overflow-hidden animate-in fade-in slide-in-from-top-2 duration-200 ${isDarkMode ? 'bg-slate-900 border-white/10 shadow-black/50' : 'bg-white border-slate-100 shadow-slate-200/50'}`}>
              <div className={`p-3 border-b flex items-center justify-between ${isDarkMode ? 'bg-slate-800/50 border-white/5' : 'bg-slate-50 border-slate-100'}`}>
                <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Cloud Index</span>
              </div>

              <div className="max-h-[350px] overflow-y-auto custom-scrollbar">
                {results.length > 0 ? (
                  results.map((prop) => (
                    <button
                      key={prop.id}
                      onClick={() => handleSelectResult(prop.id)}
                      className={`w-full flex items-center gap-4 p-4 transition-colors text-left border-b last:border-0 group ${isDarkMode ? 'hover:bg-white/5 border-white/5' : 'hover:bg-slate-50 border-slate-50'}`}
                    >
                      <img 
                        src={prop.image} 
                        alt="" 
                        className="w-12 h-12 rounded-lg object-cover shadow-sm group-hover:scale-105 transition-transform"
                      />
                      <div className="flex-1 min-w-0">
                        <p className={`text-sm font-bold truncate group-hover:text-indigo-400 transition-colors ${isDarkMode ? 'text-white' : 'text-slate-900'}`}>{prop.title}</p>
                        <div className="flex items-center gap-2 text-[10px] text-slate-500 font-medium">
                          <MapPin size={10} className="text-indigo-500" />
                          <span className="truncate">{prop.location}</span>
                        </div>
                      </div>
                    </button>
                  ))
                ) : (
                  <div className="p-8 text-center text-slate-500">Nenhum resultado.</div>
                )}
              </div>
            </div>
          )}
        </div>
      </div>

      <div className="flex items-center gap-4 md:gap-6">
        {/* Theme Toggle */}
        <button 
          onClick={onToggleTheme}
          className={`p-2.5 rounded-xl border transition-all active:scale-95 group relative overflow-hidden ${isDarkMode ? 'bg-slate-800 border-white/10 text-amber-400 hover:bg-slate-700' : 'bg-slate-50 border-slate-200 text-slate-600 hover:bg-slate-100'}`}
          title={isDarkMode ? 'Ativar Modo Claro' : 'Ativar Modo Noturno'}
        >
          {isDarkMode ? <Sun size={20} className="relative z-10" /> : <Moon size={20} className="relative z-10" />}
          <div className={`absolute inset-0 bg-gradient-to-tr transition-opacity duration-500 opacity-0 group-hover:opacity-20 ${isDarkMode ? 'from-amber-500 to-orange-500' : 'from-indigo-500 to-purple-500'}`}></div>
        </button>

        <button className={`relative p-2.5 rounded-xl transition-all group ${isDarkMode ? 'text-slate-400 hover:bg-white/5' : 'text-slate-500 hover:bg-slate-50'}`}>
          <Bell size={20} className={unreadApplications > 0 ? "text-indigo-400 animate-pulse" : ""} />
          {unreadApplications > 0 && (
            <span className="absolute top-1.5 right-1.5 w-4 h-4 bg-red-500 border-2 border-white dark:border-slate-900 rounded-full flex items-center justify-center text-[8px] font-black text-white shadow-sm">
              {unreadApplications > 9 ? '+9' : unreadApplications}
            </span>
          )}
        </button>

        <div className={`h-8 w-px ${isDarkMode ? 'bg-white/10' : 'bg-slate-200'}`}></div>

        <div className="flex items-center gap-3">
          <div className="text-right hidden sm:block">
            <p className={`text-sm font-black leading-none ${isDarkMode ? 'text-white' : 'text-slate-900'}`}>{user.name}</p>
            <p className="text-[10px] font-bold text-slate-500 mt-1 uppercase tracking-tighter">{user.role}</p>
          </div>
          <div className="relative">
             <img src={user.avatar} alt={user.name} className={`w-10 h-10 rounded-xl object-cover ring-2 ${isDarkMode ? 'ring-white/10' : 'ring-slate-100'}`} />
             <div className="absolute -bottom-1 -right-1 w-3 h-3 bg-emerald-500 rounded-full border-2 border-white dark:border-slate-900 shadow-sm"></div>
          </div>
          <button 
            onClick={onLogout}
            className="ml-2 p-2.5 text-slate-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-500/10 rounded-xl transition-colors"
            title="Sair do sistema"
          >
            <LogOut size={20} />
          </button>
        </div>
      </div>
    </header>
  );
};

export default Header;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  TrendingUp, Users, Home, 
  Wallet, Sparkles, X as CloseIcon, 
  ShieldCheck, Send, Bot, RefreshCw,
  Briefcase, ArrowRight, Bell,
  Truck, LayoutTemplate,
  ChevronRight,
  Shield,
  Settings2,
  Zap,
  Activity,
  ArrowUpRight,
  Target,
  PieChart as PieIcon,
  Cloud,
  CheckCircle,
  Clock
} from 'lucide-react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, 
  ResponsiveContainer, AreaChart, Area, PieChart, Pie, Cell
} from 'recharts';
import { supabase } from '../supabaseClient';
import { getStrategicInsight, chatWithMonteAI } from '../geminiService';
import TodoList from '../components/TodoList';

const DashboardView: React.FC = () => {
  const [stats, setStats] = useState({ 
    revenue: 0, 
    expenses: 0, 
    employees: 0, 
    properties: 0, 
    contacts: 0,
    pendingApps: 0 
  });
  const [recentMessages, setRecentMessages] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [lastSync, setLastSync] = useState(new Date());
  const [aiInsight, setAiInsight] = useState<string>('Analizando rede neural da Monte...');

  const [aiChatOpen, setAiChatOpen] = useState(false);
  const [chatInput, setChatInput] = useState('');
  const [chatMessages, setChatMessages] = useState<{role: 'user' | 'ai', text: string}[]>([
    { role: 'ai', text: 'Central Monte Imobiliária Ativa. Aguardando comandos estratégicos.' }
  ]);
  const [isAiTyping, setIsAiTyping] = useState(false);

  useEffect(() => {
    fetchGlobalStats();
  }, []);

  async function fetchGlobalStats() {
    setIsSyncing(true);
    try {
      const [txRes, empRes, propRes, contactRes, msgListRes, appCountRes] = await Promise.all([
        supabase.from('transactions').select('*'),
        supabase.from('employees').select('*', { count: 'exact', head: true }),
        supabase.from('properties').select('*', { count: 'exact', head: true }),
        supabase.from('contact_requests').select('*', { count: 'exact', head: true }),
        supabase.from('contact_requests').select('*').order('created_at', { ascending: false }).limit(3),
        supabase.from('job_applications').select('*', { count: 'exact', head: true }).eq('status', 'Pendente')
      ]);

      const txs = txRes.data || [];
      const rev = txs.filter(t => t.type === 'RECEITA').reduce((a, b) => a + Number(b.amount || 0), 0);
      const exp = txs.filter(t => t.type === 'DESPESA').reduce((a, b) => a + Number(b.amount || 0), 0);

      const newStats = {
        revenue: rev, 
        expenses: exp,
        employees: empRes.count || 0,
        properties: propRes.count || 0, 
        contacts: contactRes.count || 0,
        pendingApps: appCountRes.count || 0
      };
      setStats(newStats);
      setRecentMessages(msgListRes.data || []);
      setLastSync(new Date());

      const insight = await getStrategicInsight(`Saldo: ${rev-exp}MT, Staff: ${empRes.count}, Leads: ${contactRes.count}`);
      setAiInsight(insight);
    } catch (error: any) {
      console.error(error);
    } finally {
      setLoading(false);
      setIsSyncing(false);
    }
  }

  const handleSendToAI = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!chatInput.trim() || isAiTyping) return;
    const userMsg = chatInput;
    setChatMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setChatInput('');
    setIsAiTyping(true);
    const response = await chatWithMonteAI(userMsg, stats);
    setChatMessages(prev => [...prev, { role: 'ai', text: response }]);
    setIsAiTyping(false);
  };

  const chartData = useMemo(() => [
    { name: 'Jan', receita: stats.revenue * 0.6, despesa: stats.expenses * 0.5 },
    { name: 'Fev', receita: stats.revenue * 0.85, despesa: stats.expenses * 0.75 },
    { name: 'Mar', receita: stats.revenue, despesa: stats.expenses }
  ], [stats]);

  const pieData = [
    { name: 'Venda', value: 65, color: '#6366f1' },
    { name: 'Arrend.', value: 25, color: '#10b981' },
    { name: 'Obras', value: 10, color: '#f43f5e' },
  ];

  if (loading) return (
