import React, { useState } from 'react';
import { BarChart3, PieChart, FileText, Download, Loader2, Table, FileSpreadsheet, CheckCircle2 } from 'lucide-react';
import { supabase } from '../supabaseClient';

const ReportsView: React.FC = () => {
  const [isExporting, setIsExporting] = useState<string | null>(null);

  const exportToCSV = (data: any[], filename: string) => {
    if (data.length === 0) {
      alert("Nenhum dado disponível para exportação.");
      return;
    }

    const headers = Object.keys(data[0]);
    const csvContent = [
      headers.join(','),
      ...data.map(row => headers.map(fieldName => {
        const value = row[fieldName] === null || row[fieldName] === undefined ? "" : row[fieldName];
        return `"${String(value).replace(/"/g, '""')}"`;
      }).join(','))
    ].join('\r\n');

    const blob = new Blob(["\ufeff" + csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    const url = URL.createObjectURL(blob);
    link.setAttribute("href", url);
    link.setAttribute("download", `${filename}_${new Date().toISOString().split('T')[0]}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleExport = async (type: 'finance' | 'staff' | 'projects') => {
    setIsExporting(type);
    try {
      let data: any[] = [];
      let filename = "";

      if (type === 'finance') {
        const { data: res } = await supabase.from('transactions').select('*').order('date', { ascending: false });
        data = res || [];
        filename = "Fluxo_Caixa_Monte";
      } else if (type === 'staff') {
        const { data: res } = await supabase.from('employees').select('*').order('name');
        data = res || [];
        filename = "Base_Staff_Monte";
      } else if (type === 'projects') {
        const { data: res } = await supabase.from('projects').select('*').order('created_at');
        data = res || [];
        filename = "Projetos_Obras_Monte";
      }

      exportToCSV(data, filename);
    } catch (error) {
      console.error("Export error:", error);
    } finally {
      setIsExporting(null);
    }
  };

  const reports = [
    { 
      id: 'finance',
      title: 'Fluxo de Caixa Consolidado', 
      icon: <BarChart3 size={24} />, 
      description: 'Exportação detalhada de todas as entradas e saídas registadas na cloud.',
      action: () => handleExport('finance')
    },
    { 
      id: 'staff',
      title: 'Dossiê Geral de Staff', 
      icon: <FileSpreadsheet size={24} />, 
      description: 'Listagem completa de colaboradores, incluindo NUIT, NISS e dados de contacto.',
      action: () => handleExport('staff')
    },
    { 
      id: 'projects',
      title: 'Performance de Projetos', 
      icon: <FileText size={24} />, 
      description: 'Relatório de orçamentos vs gastos reais em todas as obras ativas.',
      action: () => handleExport('projects')
    }
  ];

  return (
    <div className="space-y-10 animate-in fade-in duration-700 pb-20">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-4xl font-black text-slate-900 tracking-tighter uppercase italic">Central de <span className="text-indigo-600">Dados</span></h1>
          <p className="text-slate-500 font-medium">Extraia inteligência operacional em formatos universais.</p>
        </div>
        <div className="flex items-center gap-2 px-6 py-2 bg-emerald-50 text-emerald-600 rounded-full border border-emerald-100 text-[10px] font-black uppercase tracking-widest">
           <CheckCircle2 size={14} /> Sincronização Cloud Ativa
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
        {reports.map((report) => (
          <div key={report.id} className="bg-white p-10 rounded-[3.5rem] border border-slate-100 shadow-xl hover:shadow-2xl transition-all flex flex-col group relative overflow-hidden">
            <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-500 opacity-[0.03] rounded-full -translate-y-1/2 translate-x-1/2"></div>

            <div className="p-5 bg-slate-50 rounded-2xl text-slate-400 group-hover:bg-indigo-600 group-hover:text-white transition-all w-fit mb-8 shadow-inner">
              {report.icon}
            </div>

            <div className="flex-1">
              <h3 className="text-xl font-black text-slate-900 group-hover:text-indigo-600 transition-colors mb-4">{report.title}</h3>
              <p className="text-sm text-slate-500 font-medium leading-relaxed mb-10">"{report.description}"</p>

              <button 
                onClick={report.action}
                disabled={isExporting !== null}
                className="w-full flex items-center justify-center gap-3 bg-slate-900 text-white py-5 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-600 transition-all active:scale-95 disabled:opacity-50"
              >
                {isExporting === report.id ? (
                  <Loader2 size={18} className="animate-spin" />
                ) : (
                  <Download size={18} />
                )}
                Exportar para CSV
              </button>
            </div>
          </div>
        ))}
      </div>

      <div className="bg-slate-900 p-16 rounded-[4.5rem] text-white relative overflow-hidden shadow-2xl">
         <div className="absolute inset-0 opacity-10" style={{ backgroundImage: 'radial-gradient(#fff 1px, transparent 1px)', backgroundSize: '24px 24px' }}></div>
         <div className="relative z-10 max-w-2xl">
            <h2 className="text-3xl font-black mb-4 tracking-tight">Precisa de um formato específico?</h2>
            <p className="text-slate-400 font-medium mb-8">Nossa infraestrutura permite a geração de relatórios personalizados para auditorias do Ministério do Trabalho ou Finanças.</p>
            <button className="px-10 py-4 bg-white text-slate-900 rounded-2xl font-black text-[10px] uppercase tracking-[0.2em] hover:bg-indigo-500 hover:text-white transition-all">Solicitar Customização</button>
         </div>
      </div>
    </div>
  );
};

