                      isActive ? `${item.activeColor} text-white shadow-lg` : 'bg-white/5 text-slate-500 group-hover:text-white group-hover:bg-white/10'
                    } group-hover:scale-110 group-hover:-rotate-3`}>
                      {item.icon}
                    </div>
                    <div className="text-left">
                      <span className={`block text-xs font-black uppercase tracking-[0.15em] leading-none mb-2 ${isActive ? 'text-white' : 'text-slate-400 group-hover:text-slate-200'}`}>{item.label}</span>
                      <span className={`text-[9px] font-bold uppercase tracking-widest ${isActive ? 'text-white/40' : 'text-slate-600 group-hover:text-slate-50'}`}>{item.sub}</span>
                    </div>
