                className="block w-full text-left px-4 py-3 text-base font-medium text-slate-700 hover:bg-slate-50 hover:text-blue-600 rounded-lg"
              >
                {link.name}
              </button>
            ))}
          </div>
        )}
      </nav>
    </div>
  );
};

